"""
This module represents the game board and piece management.
"""

class GameBoard:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ['white', 'black']
        for i, row in enumerate(range(2, 6)):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = Piece(f"{colors[0]}_{i}{j}")
            for j in range((i + 1) % 2, 8, 2):
                self.board[row + 3][j] = Piece(f"{colors[1]}_{row + 3}{j}")

    def move_piece(self, start, end):
        x_start, y_start = int(start[0]), int(start[1])
        x_end, y_end = int(end[0]), int(end[1])
        piece = self.board[x_start][y_start]
        if piece:
            self.board[x_start][y_start] = None
            self.board[x_end][y_end] = piece
